1	const PROCESSING_FEE = 5;
2	const BLOCK_PRICE = 60;
3	const BLOCK_SIZE = 3;
4	
5	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	type Item = { type: string; cursed?: boolean; enchantment?: number };
17	type Step = { items: Item[] };
18	type Customer = {
19	  yearsWithMHPCO: number;
20	  isFirstInsurance?: boolean;
21	  isFollowUpContract?: boolean;
22	};
23	type Scenario = { customer: Customer; steps: Step[] };
24	
25	const basePremiumFor = (type: string): number =>
26	  BASE_PREMIUM_BY_ITEM_TYPE[type] ?? 0;
27	
28	const isBlockOfAlikeComponents = (type: string, count: number): boolean =>
29	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
30	
31	const priceForGroup = (type: string, count: number): number =>
32	  isBlockOfAlikeComponents(type, count)
33	    ? BLOCK_PRICE
34	    : count * basePremiumFor(type);
35	
36	const countByType = (items: Item[]): Map<string, number> => {
37	  const counts = new Map<string, number>();
38	  for (const item of items) {
39	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
40	  }
41	  return counts;
42	};
43	
44	const CURSE_SURCHARGE_RATE = 0.5;
45	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
46	const HIGH_ENCHANTMENT_THRESHOLD = 5;
47	
48	const isHighlyEnchanted = (item: Item): boolean =>
49	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
50	
51	const surchargeRate = (item: Item): number =>
52	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
53	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
54	
55	const itemSurcharge = (item: Item): number =>
56	  basePremiumFor(item.type) * surchargeRate(item);
57	
58	const sumGroupedPrices = (items: Item[]): number =>
59	  [...countByType(items)].reduce(
60	    (total, [type, count]) => total + priceForGroup(type, count),
61	    0,
62	  );
63	
64	const sumItemSurcharges = (items: Item[]): number =>
65	  items.reduce((total, item) => total + itemSurcharge(item), 0);
66	
67	const LOYALTY_DISCOUNT_RATE = 0.2;
68	const LOYALTY_THRESHOLD = 2;
69	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
70	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
71	
72	const isLongStandingCustomer = (customer: Customer): boolean =>
73	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD;
74	
75	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
76	  isLongStandingCustomer(customer) ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
77	
78	const firstInsuranceSurcharge = (policyBase: number, customer: Customer): number =>
79	  customer.isFirstInsurance ? policyBase * FIRST_INSURANCE_SURCHARGE_RATE : 0;
80	
81	const followUpDiscount = (policyBase: number, customer: Customer): number =>
82	  customer.isFollowUpContract ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
83	
84	const customerAdjustment = (policyBase: number, customer: Customer): number =>
85	  firstInsuranceSurcharge(policyBase, customer)
86	  - loyaltyDiscount(policyBase, customer)
87	  - followUpDiscount(policyBase, customer);
88	
89	const quotePremiumFor = (step: Step, customer: Customer): number => {
90	  const policyBase = sumGroupedPrices(step.items);
91	  return policyBase
92	    + customerAdjustment(policyBase, customer)
93	    + sumItemSurcharges(step.items)
94	    + PROCESSING_FEE;
95	};
96	
97	export const processScenario = (input: unknown): unknown => {
98	  const { customer, steps } = input as Scenario;
99	  return {
100	    results: steps.map((step) => ({ premium: Math.ceil(quotePremiumFor(step, customer)) })),
101	  };
102	};
